{"code": "import os

def parse_theta_results(fname):
    # Read the file
    with open(fname, 'r') as f:
        lines = f.readlines()

    # Filter out blank lines, strip whitespace
    non_blank = []
    for line in lines:
        stripped = line.strip()
        if stripped:
            non_blank.append(stripped)

    if len(non_blank) < 2:
        # Need header and at least one data line
        return {'NLL': None, 'mu_normal': None, 'mu_tumors': [], 'C': [], 'p*': []}

    # Parse header
    header = non_blank[0].split('\t')

    # Parse data line
    data = non_blank[1].split('\t')

    # Build dictionary
    result = {}

    for i, col_name in enumerate(header):
        col_name = col_name.strip()
        if i >= len(data):
            val = ''
        else:
            val = data[i].strip()

        if col_name == 'NLL':
            if val == '':
                result['NLL'] = None
            else:
                result['NLL'] = float(val)
        elif col_name == 'mu':
            if val == '':
                result['mu_normal'] = None
                result['mu_tumors'] = []
            else:
                parts = val.split(',')
                result['mu_normal'] = float(parts[0])
                result['mu_tumors'] = [float(p) for p in parts[1:]]
        elif col_name == 'C':
            if val == '':
                result['C'] = []
            else:
                # parse C
                groups = val.split(':')
                result['C'] = []
                for g in groups:
                    inner = []
                    for item in g.split(','):
                        item = item.strip()
                        if item.lower() in ('na', '?', '.', 'none', 'n/a', '-') or item == '':
                            inner.append(None)
                        else:
                            inner.append(int(item))
                    result['C'].append(inner)
        elif col_name == 'p*':
            if val == '':
                result['p*'] = []
            else:
                items = val.split(',')
                inner = []
                for item in items:
                    item = item.strip()
                    if item.lower() in ('na', '?', '.', 'none', 'n/a', '-') or item == '':
                        inner.append(None)
                    else:
                        inner.append(float(item))
                result['p*'] = inner  # flat list

    return result

